class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows deserialization of explicitly
    allowlisted classes. This prevents arbitrary code execution via
    crafted pickle payloads (e.g., using __reduce__ to call os.system).
    """

    def find_class(self, module: str, name: str) -> type:
        # Check if the module is in the blocked list
        module_root = module.split(".")[0]
        if module_root in BLOCKED_MODULES or module in BLOCKED_MODULES:
            logger.warning(
                f"Blocked deserialization attempt: {module}.{name}"
            )
            raise pickle.UnpicklingError(
                f"Deserialization of '{module}.{name}' is not allowed. "
                f"Module '{module}' is blocked for security reasons."
            )

        # Check if the specific class is in the allowlist
        if (module, name) in ALLOWED_CLASSES:
            return super().find_class(module, name)

        # Allow sklearn submodules that are part of estimator internals
        # but still verify they're actual sklearn components
        if module.startswith("sklearn.") and not any(
            blocked in module for blocked in BLOCKED_MODULES
        ):
            # Allow sklearn internal types needed for model reconstruction
            # but log them for monitoring
            logger.info(
                f"Allowing sklearn internal class: {module}.{name}"
            )
            try:
                cls = super().find_class(module, name)
                return cls
            except (AttributeError, ModuleNotFoundError):
                raise pickle.UnpicklingError(
                    f"Class '{module}.{name}' not found in sklearn."
                )

        # Allow numpy internal types needed for array reconstruction
        if module.startswith("numpy.") and not any(
            blocked in module for blocked in BLOCKED_MODULES
        ):
            logger.info(f"Allowing numpy internal class: {module}.{name}")
            try:
                cls = super().find_class(module, name)
                return cls
            except (AttributeError, ModuleNotFoundError):
                raise pickle.UnpicklingError(
                    f"Class '{module}.{name}' not found in numpy."
                )

        logger.warning(
            f"Rejected deserialization of non-allowlisted class: {module}.{name}"
        )
        raise pickle.UnpicklingError(
            f"Deserialization of '{module}.{name}' is not allowed. "
            f"Only allowlisted sklearn model classes are permitted."
        )


def safe_pickle_load(data: bytes) -> Any:
    """
    Safely deserialize a pickle payload using the RestrictedUnpickler.
    This prevents arbitrary code execution from malicious pickle files.
    """
    return RestrictedUnpickler(io.BytesIO(data)).load()


def validate_pickle_header(data: bytes) -> bool:
    """Validate that the data starts with a valid pickle protocol header."""
    if len(data) < 2:
        return False
    # Check for valid pickle opcodes at the start
    first_byte = data[0]
    # Protocol 0-5 start bytes
    valid_starts = {
        0x80,  # PROTO opcode (protocol 2+)
        0x28,  # MARK
        0x7D,  # EMPTY_DICT
        0x5D,  # EMPTY_LIST
        0x29,  # EMPTY_TUPLE
        0x89,  # NEWOBJ_EX (protocol 4)
    }
    # Also allow text-mode pickle (protocol 0)
    if first_byte in valid_starts or chr(first_byte) in "({[dltI":
        return True
    return False


def compute_file_hash(data: bytes) -> str:
    """Compute SHA-256 hash of the file for integrity tracking."""
    return hashlib.sha256(data).hexdigest()


def validate_model(model: Any) -> Dict[str, Any]:
    """
    Validate that the deserialized object is a legitimate sklearn model.
    Returns model metadata if valid, raises exception otherwise.
    """
    model_info = {
        "type": type(model).__name__,
        "module": type(model).__module__,
    }

    # Check if it's a sklearn estimator or pipeline
    if isinstance(model, sklearn.base.BaseEstimator):
        model_info["is_sklearn_estimator"] = True
        model_info["params"] = {
            k: str(v) for k, v in model.get_params(deep=False).items()
        }

        # Check if the model has been fitted
        try:
            sklearn.utils.validation.check_is_fitted(model)
            model_info["is_fitted"] = True
        except sklearn.exceptions.NotFittedError:
            model_info["is_fitted"] = False

        return model_info

    raise ValueError(
        f"Deserialized object is not a valid sklearn estimator. "
        f"Got type: {type(model).__name__} from module: {type(model).__module__}"
    )


