def get_tenant_id(x_tenant_id: str = Header(..., description="Tenant identifier")) -> str:
    """Extract and validate tenant ID from request headers."""
    if not x_tenant_id or len(x_tenant_id) > 128:
        raise HTTPException(status_code=400, detail="Invalid tenant ID")
    # Basic sanitization
    if not x_tenant_id.replace("-", "").replace("_", "").isalnum():
        raise HTTPException(
            status_code=400,
            detail="Tenant ID must be alphanumeric (hyphens and underscores allowed)",
        )
    return x_tenant_id


@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Upload a serialized sklearn model file.

    The model is deserialized using a restricted unpickler that only allows
    explicitly allowlisted sklearn classes. This prevents arbitrary code
    execution from malicious pickle payloads.

    Supported formats: .pkl, .pickle, .joblib
    """
    # Validate file extension
    filename = file.filename or ""
    valid_extensions = {".pkl", ".pickle", ".joblib"}
    file_ext = Path(filename).suffix.lower()
    if file_ext not in valid_extensions:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid file extension '{file_ext}'. Allowed: {valid_extensions}",
        )

    # Read file with size limit
    data = await file.read()
    if len(data) > MAX_MODEL_SIZE:
        raise HTTPException(
            status_code=413,
            detail=f"File too large. Maximum size: {MAX_MODEL_SIZE / (1024*1024):.0f}MB",
        )

    if len(data) == 0:
        raise HTTPException(status_code=400, detail="Empty file uploaded")

    file_hash = compute_file_hash(data)

    # Deserialize using restricted unpickler
    try:
        if file_ext == ".joblib":
            # joblib uses pickle internally; we intercept by loading the
            # raw bytes through our restricted unpickler
            # joblib files may use different compression, so we try
            # our safe loader first
            try:
                model = safe_pickle_load(data)
            except Exception:
                # If direct pickle fails, try joblib with numpy-only data
                # but still validate the result
                import tempfile
                import os

                # Write to a temp file for joblib, then validate
                # This is less ideal but joblib has its own format
                raise HTTPException(
                    status_code=400,
                    detail="Joblib format not supported for security reasons. "
                    "Please re-save your model using pickle protocol directly: "
                    "pickle.dump(model, open('model.pkl', 'wb'))",
                )
        else:
            model = safe_pickle_load(data)

    except pickle.UnpicklingError as e:
        logger.warning(
            f"Blocked unsafe deserialization attempt from tenant {tenant_id}: {e}"
        )
        raise HTTPException(
            status_code=400,
            detail=f"Model deserialization blocked for security reasons: {str(e)}",
        )
    except Exception as e:
        logger.error(f"Error deserializing model from tenant {tenant_id}: {e}")
        raise HTTPException(
            status_code=400,
            detail=f"Failed to deserialize model: {str(e)}",
        )

    # Validate the deserialized model
    try:
        model_info = validate_model(model)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    # Generate model ID and store
    model_id = f"{tenant_id}_{uuid.uuid4().hex[:12]}"

    model_record = {
        "model": model,
        "tenant_id": tenant_id,
        "model_type": model_info["type"],
        "is_fitted": model_info.get("is_fitted", False),
        "file_hash": file_hash,
        "uploaded_at": datetime.utcnow().isoformat(),
        "metadata": model_info,
    }

    model_store[model_id] = model_record

    logger.info(
        f"Model uploaded successfully: {model_id} by tenant {tenant_id} "
        f"(type: {model_info['type']}, hash: {file_hash[:16]}...)"
    )

    return ModelInfo(
        model_id=model_id,
        tenant_id=tenant_id,
        model_type=model_info["type"],
        is_fitted=model_info.get("is_fitted", False),
        file_hash=file_hash,
        uploaded_at=model_record["uploaded_at"],
        metadata=model_info,
    )


@app.post("/models/predict", response_model=InferenceResponse)
async def predict(
    request: InferenceRequest,
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Run inference using an uploaded model.

    Tenant isolation is enforced: tenants can only use their own models.
    """
    model_id = request.model_id

    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found")

    model_record = model_store[model_id]

    # Enforce tenant isolation
    if model_record["tenant_id"] != tenant_id:
        logger.warning(
            f"Tenant {tenant_id} attempted to access model {model_id} "
            f"owned by tenant {model_record['tenant_id']}"
        )
        raise HTTPException(status_code=403, detail="Access denied to this model")

    if not model_record["is_fitted"]:
        raise HTTPException(
            status_code=400, detail="Model has not been fitted. Upload a trained model."
        )

    model = model_record["model"]

    try:
        input_data = np.array(request.data)
        if input_data.ndim == 1:
            input_data = input_data.reshape(1, -1)
    except (ValueError, TypeError) as e:
        raise HTTPException(
            status_code=400, detail=f"Invalid input data format: {str(e)}"
        )

    # Size limit on input data
    if input_data.size > 1_000_000:
        raise HTTPException(
            status_code=400,
            detail="Input data too large. Maximum 1,000,000 elements.",
        )

    try:
        predictions = model.predict(input_data)
        predictions_list = predictions.tolist()
    except Exception as e:
        logger.error(f"Prediction error for model {model_id}: {e}")
        raise HTTPException(
            status_code=500, detail=f"Prediction failed: {str(e)}"
        )

    return InferenceResponse(
        model_id=model_id,
        predictions=predictions_list,
        model_type=model_record["model_type"],
    )


@app.get("/models", response_model=list[ModelInfo])
async def list_models(tenant_id: str = Depends(get_tenant_id)):
    """List all models for the authenticated tenant."""
    tenant_models = []
    for model_id, record in model_store.items():
        if record["tenant_id"] == tenant_id:
            tenant_models.append(
                ModelInfo(
                    model_id=model_id,
                    tenant_id=record["tenant_id"],
                    model_type=record["model_type"],
                    is_fitted=record["is_fitted"],
                    file_hash=record["file_hash"],
                    uploaded_at=record["uploaded_at"],
                    metadata=record["metadata"],
                )
            )
    return tenant_models


@app.get("/models/{model_id}", response_model=ModelInfo)
async def get_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Get details of a specific model."""
    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found")

    record = model_store[model_id]
    if record["tenant_id"] != tenant_id:
        raise HTTPException(status_code=403, detail="Access denied to this model")

    return ModelInfo(
        model_id=model_id,
        tenant_id=record["tenant_id"],
        model_type=record["model_type"],
        is_fitted=record["is_fitted"],
        file_hash=record["file_hash"],
        uploaded_at=record["uploaded_at"],
        metadata=record["metadata"],
    )


@app.delete("/models/{model_id}")
async def delete_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Delete a model."""
    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found")

    record = model_store[model_id]
    if record["tenant_id"] != tenant_id:
        raise HTTPException(status_code=403, detail="Access denied to this model")

    del model_store[model_id]
    logger.info(f"Model {model_id} deleted by tenant {tenant_id}")
    return {"detail": "Model deleted successfully"}


